 28→public interface IQueue
 29→{
 30→    QueueItem? Dequeue();
 31→    int Count { get; }
 32→}
 33→
 34→public interface IItemProcessor
 35→{
 36→    Task ProcessAsync(QueueItem item);
 37→}
 38→
 39→public interface IDeadLetterQueue
 40→{
 41→    void Enqueue(QueueItem item, string reason);
 42→    IReadOnlyList<DeadLetterEntry> GetAll();
 43→    int Count { get; }
 44→}
 45→
 46→public interface IProgressReporter
 47→{
 48→    void ReportProcessed(QueueItem item);
 49→    void ReportRetrying(QueueItem item, int attempt, int maxRetries, TimeSpan delay);
 50→    void ReportFailed(QueueItem item, string reason);
 51→    void ReportSummary(PipelineSummary summary);
 52→}
 53→
 54→// --- Retry policy with exponential backoff ---
 55→
 56→public class RetryPolicy
 57→{
 58→    public int MaxRetries { get; set; } = 3;
 59→    public TimeSpan BaseDelay { get; set; } = TimeSpan.FromMilliseconds(100);
 60→
 61→    /// <summary>Delay = BaseDelay * 2^attempt</summary>
 62→    public TimeSpan GetDelay(int attempt) =>
 63→        TimeSpan.FromMilliseconds(BaseDelay.TotalMilliseconds * Math.Pow(2, attempt));
 64→
 65→    public bool ShouldRetry(int currentAttempt) => currentAttempt < MaxRetries;
 66→}
