 68→// --- In-memory implementations ---
 69→
 70→public class InMemoryQueue : IQueue
 71→{
 72→    private readonly Queue<QueueItem> _items;
 73→    public InMemoryQueue(IEnumerable<QueueItem> items) => _items = new Queue<QueueItem>(items);
 74→    public int Count => _items.Count;
 75→    public QueueItem? Dequeue() => _items.Count > 0 ? _items.Dequeue() : null;
 76→}
 77→
 78→public class InMemoryDeadLetterQueue : IDeadLetterQueue
 79→{
 80→    private readonly List<DeadLetterEntry> _entries = new();
 81→    public int Count => _entries.Count;
 82→    public void Enqueue(QueueItem item, string reason) => _entries.Add(new DeadLetterEntry(item, reason));
 83→    public IReadOnlyList<DeadLetterEntry> GetAll() => _entries.AsReadOnly();
 84→}
