 86→// --- Console progress reporter ---
 87→
 88→public class ConsoleProgressReporter : IProgressReporter
 89→{
 90→    public void ReportProcessed(QueueItem item) =>
 91→        Console.WriteLine($"  [OK]    Processed item {item.Id}");
 92→
 93→    public void ReportRetrying(QueueItem item, int attempt, int maxRetries, TimeSpan delay) =>
 94→        Console.WriteLine($"  [RETRY] Item {item.Id} - attempt {attempt}/{maxRetries} (waiting {delay.TotalMilliseconds:F0}ms)");
 95→
 96→    public void ReportFailed(QueueItem item, string reason) =>
 97→        Console.WriteLine($"  [FAIL]  Item {item.Id} - {reason}");
 98→
 99→    public void ReportSummary(PipelineSummary summary)
100→    {
101→        Console.WriteLine();
102→        Console.WriteLine("=== Pipeline Summary ===");
103→        Console.WriteLine($"  Total items:     {summary.TotalItems}");
104→        Console.WriteLine($"  Processed:       {summary.Processed}");
105→        Console.WriteLine($"  Failed:          {summary.Failed}");
106→        Console.WriteLine($"  Total retries:   {summary.TotalRetries}");
107→        if (summary.DeadLetterItems.Count > 0)
108→        {
109→            Console.WriteLine();
110→            Console.WriteLine("  Dead-letter queue:");
111→            foreach (var entry in summary.DeadLetterItems)
112→                Console.WriteLine($"    - {entry.Item.Id}: {entry.Reason}");
113→        }
114→        Console.WriteLine("========================");
115→    }
116→}
