118→// --- Simulated processor that randomly fails ---
119→
120→public class RandomFailureProcessor : IItemProcessor
121→{
122→    private readonly Random _rng;
123→    private readonly double _failureRate;
124→
125→    public RandomFailureProcessor(double failureRate = 0.4, int? seed = null)
126→    {
127→        _failureRate = failureRate;
128→        _rng = seed.HasValue ? new Random(seed.Value) : new Random();
129→    }
130→
131→    public Task ProcessAsync(QueueItem item)
132→    {
133→        if (_rng.NextDouble() < _failureRate)
134→            throw new InvalidOperationException($"Random processing error for item {item.Id}");
135→
136→        return Task.CompletedTask;
137→    }
138→}
139→
140→// --- Pipeline processor ---
141→
142→public class PipelineProcessor
143→{
144→    private readonly IQueue _queue;
145→    private readonly IItemProcessor _processor;
146→    private readonly IDeadLetterQueue _deadLetterQueue;
147→    private readonly IProgressReporter _reporter;
148→    private readonly RetryPolicy _retryPolicy;
149→
150→    public PipelineProcessor(
151→        IQueue queue, IItemProcessor processor, IDeadLetterQueue deadLetterQueue,
152→        IProgressReporter reporter, RetryPolicy retryPolicy)
153→    {
154→        _queue = queue;
155→        _processor = processor;
156→        _deadLetterQueue = deadLetterQueue;
157→        _reporter = reporter;
158→        _retryPolicy = retryPolicy;
159→    }
160→
161→    public async Task<PipelineSummary> ProcessAllAsync()
162→    {
163→        int totalItems = 0, processed = 0, failed = 0, totalRetries = 0;
164→
165→        QueueItem? item;
166→        while ((item = _queue.Dequeue()) is not null)
167→        {
168→            totalItems++;
169→            if (await ProcessWithRetryAsync(item, ref totalRetries))
170→            {
171→                processed++;
172→                _reporter.ReportProcessed(item);
173→            }
174→            else
175→            {
176→                failed++;
177→            }
178→        }
179→
180→        var summary = new PipelineSummary(totalItems, processed, failed, totalRetries, _deadLetterQueue.GetAll());
181→        _reporter.ReportSummary(summary);
182→        return summary;
183→    }
184→
185→    private async Task<bool> ProcessWithRetryAsync(QueueItem item, ref int totalRetries)
186→    {
187→        int attempt = 0;
188→        while (true)
189→        {
190→            try
191→            {
192→                await _processor.ProcessAsync(item);
193→                return true;
194→            }
195→            catch (Exception ex)
196→            {
197→                if (_retryPolicy.ShouldRetry(attempt))
198→                {
199→                    attempt++;
200→                    totalRetries++;
201→                    var delay = _retryPolicy.GetDelay(attempt - 1);
202→                    _reporter.ReportRetrying(item, attempt, _retryPolicy.MaxRetries, delay);
203→                    await Task.Delay(delay);
204→                }
205→                else
206→                {
207→                    var reason = $"Failed after {attempt} retries: {ex.Message}";
208→                    _deadLetterQueue.Enqueue(item, reason);
209→                    _reporter.ReportFailed(item, reason);
210→                    return false;
211→                }
212→            }
213→        }
214→    }
215→}
216→
217→// --- Main entry point ---
218→
219→Console.WriteLine("Error Retry Pipeline Demo");
220→Console.WriteLine("=========================");
221→Console.WriteLine();
222→
223→// Create 10 items to process
224→var items = Enumerable.Range(1, 10)
225→    .Select(i => new QueueItem($"ITEM-{i:D3}", $"payload-{i}"))
226→    .ToArray();
227→
228→var queue = new InMemoryQueue(items);
229→var dlq = new InMemoryDeadLetterQueue();
230→var reporter = new ConsoleProgressReporter();
231→
232→// Use a seeded random processor for reproducible demo output (40% failure rate)
233→var processor = new RandomFailureProcessor(failureRate: 0.4, seed: 42);
234→
235→// Configure retry: up to 3 retries with 50ms base delay (short for demo)
236→var retryPolicy = new RetryPolicy { MaxRetries = 3, BaseDelay = TimeSpan.FromMilliseconds(50) };
237→
238→var pipeline = new PipelineProcessor(queue, processor, dlq, reporter, retryPolicy);
239→
240→Console.WriteLine($"Processing {items.Length} items (max {retryPolicy.MaxRetries} retries, {retryPolicy.BaseDelay.TotalMilliseconds}ms base delay)...");
241→Console.WriteLine();
242→
243→var summary = await pipeline.ProcessAllAsync();
244→
245→// Exit with non-zero code if any items failed permanently
246→return summary.Failed > 0 ? 1 : 0;
