 24→        _processor = processor ?? throw new ArgumentNullException(nameof(processor));
 25→        _deadLetterQueue = deadLetterQueue ?? throw new ArgumentNullException(nameof(deadLetterQueue));
 26→        _reporter = reporter ?? throw new ArgumentNullException(nameof(reporter));
 27→        _retryPolicy = retryPolicy ?? throw new ArgumentNullException(nameof(retryPolicy));
 28→        _useRealDelay = useRealDelay;
 29→    }
 30→
 31→    /// <summary>
 32→    /// Processes all items from the queue with retry logic and produces a summary.
 33→    /// </summary>
 34→    public async Task<PipelineSummary> ProcessAllAsync()
 35→    {
 36→        int totalItems = 0;
 37→        int processed = 0;
 38→        int failed = 0;
 39→        int totalRetries = 0;
 40→
 41→        // Drain the queue item by item
 42→        QueueItem? item;
 43→        while ((item = _queue.Dequeue()) is not null)
 44→        {
 45→            totalItems++;
 46→            var success = await ProcessWithRetryAsync(item, ref totalRetries);
 47→
 48→            if (success)
 49→            {
 50→                processed++;
 51→                _reporter.ReportProcessed(item);
 52→            }
 53→            else
 54→            {
 55→                failed++;
 56→            }
 57→        }
 58→
 59→        var summary = new PipelineSummary(
 60→            totalItems,
 61→            processed,
 62→            failed,
 63→            totalRetries,
 64→            _deadLetterQueue.GetAll());
 65→
 66→        _reporter.ReportSummary(summary);
 67→        return summary;
 68→    }
 69→
 70→    /// <summary>
 71→    /// Attempts to process a single item, retrying on failure with exponential backoff.
 72→    /// Returns true if the item was eventually processed successfully.
 73→    /// </summary>
 74→    private async Task<bool> ProcessWithRetryAsync(QueueItem item, ref int totalRetries)
 75→    {
 76→        int attempt = 0;
 77→
 78→        while (true)
 79→        {
 80→            try
 81→            {
 82→                await _processor.ProcessAsync(item);
 83→                return true; // Success
 84→            }
 85→            catch (Exception ex)
 86→            {
 87→                // Check if we can retry
 88→                if (_retryPolicy.ShouldRetry(attempt))
 89→                {
 90→                    attempt++;
 91→                    totalRetries++;
 92→                    var delay = _retryPolicy.GetDelay(attempt - 1);
 93→                    _reporter.ReportRetrying(item, attempt, _retryPolicy.MaxRetries, delay);
 94→
 95→                    // Apply delay (skipped in tests for speed)
 96→                    if (_useRealDelay)
 97→                    {
 98→                        await Task.Delay(delay);
 99→                    }
100→                }
101→                else
102→                {
103→                    // Exhausted all retries - send to dead-letter queue
104→                    var reason = $"Failed after {attempt} retries: {ex.Message}";
105→                    _deadLetterQueue.Enqueue(item, reason);
106→                    _reporter.ReportFailed(item, reason);
107→                    return false;
108→                }
109→            }
110→        }
111→    }
112→}
